<main class="mail-wrap" id="mail-wrap"><aside class="list-pane"><div class="list-tools"><button class="tab on" data-folder="inbox">Inbox</button><button class="tab" data-folder="sentitems">Sent</button><button class="tab" data-folder="drafts">Drafts</button><button class="tab" data-folder="junkemail">Junk</button><button class="btn btn-sm btn-gold" id="compose-btn">Compose</button></div><div class="search-row"><input id="search" placeholder="Search mail..."><button class="btn btn-sm" id="search-btn">Search</button></div><div class="msg-list" id="msg-list"><div class="empty">Loading mail...</div></div><div class="list-more"><button class="btn btn-sm" id="more-btn" style="display:none">Load More</button></div></aside><section class="read-pane" id="read-pane"><div class="read-empty" id="read-empty">Select an email to read it.</div><div id="read-content" style="display:none;min-height:0;flex:1;flex-direction:column;overflow:hidden"><div class="read-top-pane"><div class="read-head"><div class="read-subj" id="read-subj"></div><div class="read-meta" id="read-meta"></div><div class="read-actions"><button class="btn btn-sm btn-gold" id="reply-btn">Reply</button><button class="btn btn-sm" id="reply-all-btn">Reply All</button><button class="btn btn-sm" id="forward-btn">Forward</button><button class="btn btn-sm" id="mark-btn">Mark Unread</button><div class="tag-picker" id="tag-picker"><button class="btn btn-sm" id="tag-picker-btn" type="button">Tag</button><div class="tag-menu" id="tag-menu"></div></div><button class="btn btn-sm" id="remind-btn" type="button">Remind Me</button></div></div><div class="read-body"><iframe id="body-frame" sandbox="allow-same-origin allow-popups allow-popups-to-escape-sandbox"></iframe></div><div class="attach-bar" id="attach-bar"><span class="attach-label">Attachments</span><div id="attach-chips" style="display:flex;gap:8px;flex-wrap:wrap;flex:1"></div></div></div><div class="read-splitter" id="read-splitter" role="separator" aria-orientation="horizontal" title="Drag to resize email and reply panes"></div><div class="reply-pane" id="reply-pane"><div class="quick-row" id="quick-row"></div><div class="reply-box" id="reply-box"><div style="display:flex;gap:8px;align-items:center;margin-bottom:8px;flex-wrap:wrap"><button class="btn btn-sm" id="reply-template-btn" type="button">Templates</button><button class="ai-draft-btn" id="ai-draft-btn" type="button"><span id="ai-draft-btn-icon">AI</span><span id="ai-draft-btn-label">Draft with AI</span></button><select id="reply-mode"><option value="reply">Reply</option><option value="replyAll">Reply all</option></select><span style="font-size:11px;color:#64748b;margin-left:auto">Fill in bracketed placeholders before sending</span></div><div class="tpl-drawer" id="reply-template-drawer"><div class="tpl-header-row"><div class="tpl-header">Pick a reply template</div><button class="btn btn-sm tpl-manager-action" type="button" data-open-template-manager>+ Add Template</button></div><div class="tpl-list" id="reply-template-list"></div></div><div class="ai-draft-banner" id="ai-draft-banner"><span class="ai-draft-banner-text"><b>AI drafted</b> - review and edit before sending. Verify dates, pricing, and product details.</span><div class="ai-draft-actions"><button class="ai-mini-btn" id="ai-draft-again" type="button">Try again</button><button class="ai-mini-btn dismiss" id="ai-draft-dismiss" type="button">Hide</button></div></div><textarea id="reply-text" placeholder="Type your reply... or pick a template above"></textarea><label class="file-row"><span>Attachments</span><input id="reply-files" type="file" multiple></label><div class="reply-foot"><div></div><div><button class="btn btn-sm" id="cancel-reply">Cancel</button><button class="btn btn-sm btn-gold" id="send-reply">Send Reply</button></div></div></div></div></div></section><aside class="context-pane"><div class="context-title">Related Context</div><div id="context-body" class="context-empty">Open an email to match customer records, quotes, jobs, and ClickUp links.</div><div class="context-section" id="reminders-panel"><h3>Reminders</h3><div id="reminders-panel-list" class="context-empty">No reminders loaded.</div></div><div class="context-section"><h3>Next Pass</h3><div class="planned-actions"><button class="btn btn-sm" id="next-link-customer" type="button">Create / Link Customer</button><button class="btn btn-sm" id="next-create-lead" type="button">Create Lead From Email</button><button class="btn btn-sm" id="next-save-job-note" type="button">Save Email As Job Note</button></div></div></aside></main>
<div class="modal-overlay" id="compose-modal"><div class="modal-box"><div class="modal-head"><h2>Compose Email</h2><button class="modal-close" id="modal-close" type="button">×</button></div><div class="modal-body"><div class="template-manager-tools" style="margin:0 0 8px"><label style="margin:0">Template</label><button class="mbtn mbtn-ghost tpl-manager-action" type="button" data-open-template-manager>+ Add Template</button></div><div class="tpl-list" id="compose-template-list"></div><label>To</label><input id="to-field" placeholder="name@example.com"><label>CC</label><input id="cc-field" placeholder="Optional"><label>Subject</label><input id="subject-field"><label>Message</label><textarea id="html-field"></textarea><label>Attachments / Images</label><input id="compose-files" type="file" multiple><div class="safety" style="margin-top:12px">Before sending attachments or links outside OGM, confirm they are customer-safe and do not include internal pricing, cost, or admin notes.</div></div><div class="modal-foot"><button class="mbtn mbtn-ghost" id="compose-cancel">Cancel</button><button class="mbtn mbtn-gold" id="compose-send">Send</button></div></div></div>
<div class="modal-overlay" id="reminder-modal"><div class="modal-box" style="max-width:520px"><div class="modal-head"><h2>Set Reminder</h2><button class="modal-close" id="reminder-close" type="button">×</button></div><div class="modal-body"><label>When</label><div style="display:flex;gap:8px;flex-wrap:wrap;margin-bottom:10px"><button class="btn btn-sm" type="button" data-rem-hours="2">2 Hours</button><button class="btn btn-sm" type="button" data-rem-hours="24">Tomorrow</button><button class="btn btn-sm" type="button" data-rem-hours="72">3 Days</button><button class="btn btn-sm" type="button" data-rem-hours="168">1 Week</button></div><input id="reminder-due" type="datetime-local"><label>Note</label><textarea id="reminder-note" style="min-height:90px" placeholder="Optional reminder note"></textarea></div><div class="modal-foot"><button class="mbtn mbtn-ghost" id="reminder-cancel">Cancel</button><button class="mbtn mbtn-gold" id="reminder-save">Save Reminder</button></div></div></div>
<div class="modal-overlay" id="job-modal"><div class="modal-box" style="max-width:680px"><div class="modal-head"><h2>Save Attachment To Job</h2><button class="modal-close" id="job-close" type="button">×</button></div><div class="modal-body"><div class="safety"><strong>Safety check:</strong> only upload customer/job documents. Do not upload internal pricing, cost sheets, passwords, or private OGM files.</div><p id="job-attach-name" style="font-size:13px;margin-bottom:12px;color:#4a4538"></p><div class="job-search"><input id="job-search" placeholder="Search customer or job..."><button class="btn btn-sm" id="job-search-btn" type="button">Search</button></div><div class="job-list" id="job-list"><div class="context-empty">Search for a job to attach this email file.</div></div></div><div class="modal-foot"><button class="mbtn mbtn-ghost" id="job-cancel">Cancel</button></div></div></div>
<div class="modal-overlay" id="template-modal"><div class="modal-box" style="max-width:880px"><div class="modal-head"><h2>Email Templates</h2><button class="modal-close" id="template-close" type="button">×</button></div><div class="modal-body"><div class="safety"><strong>Manager tool:</strong> these templates are shared across Email Center. Bracketed text such as [Name] or [date] is treated as a placeholder and staff will be warned before sending if it is still present.</div><div class="template-manager-tools"><button class="mbtn mbtn-gold" id="template-add-top" type="button">+ Add Template</button><span>Managers can add as many shared reply and compose templates as the team needs.</span></div><div class="template-editor-list" id="template-editor-list"></div><button class="mbtn mbtn-ghost" id="template-add" type="button" style="margin-top:12px">Add Another Template</button></div><div class="modal-foot"><button class="mbtn mbtn-ghost" id="template-reset" type="button">Reset Defaults</button><button class="mbtn mbtn-ghost" id="template-cancel" type="button">Cancel</button><button class="mbtn mbtn-gold" id="template-save" type="button">Save Templates</button></div></div></div>
<div class="toast" id="toast"></div>
<script>
const API='email-api.php';
const TAGS={lead:'Lead',quote:'Quote',follow:'Follow-Up',scheduled:'Scheduled',resolved:'Resolved'};
const TAG_CLASSES={lead:'tag-lead',quote:'tag-quote',follow:'tag-follow',scheduled:'tag-scheduled',resolved:'tag-resolved'};
let TEMPLATES=[
 {id:'thanks',title:'Thanks / Received',note:'Quick acknowledgement',subject:'Thank you for reaching out',body:'Hi [Name],\n\nThanks for reaching out. I received your message and will get back to you shortly.\n\nThank you,'},
 {id:'quote-ready',title:'Quote Ready',note:'Send quote/proposal link',subject:'Your OGM proposal',body:'Hi [Name],\n\nYour proposal is ready for review. Please let me know if you have any questions or would like to make adjustments.\n\nThank you,'},
 {id:'follow-up',title:'Quote Follow-Up',note:'Follow up after quote',subject:'Following up on your OGM proposal',body:'Hi [Name],\n\nI wanted to follow up on the proposal we sent over. Let me know if you have any questions or if you would like us to adjust anything.\n\nThank you,'},
 {id:'template-ready',title:'Ready To Template',note:'Schedule template appointment',subject:'Ready to schedule your template',body:'Hi [Name],\n\nWe are ready to schedule your template appointment. What days work best for you?\n\nThank you,'},
 {id:'install-confirm',title:'Install Confirmed',note:'Install appointment note',subject:'Installation confirmation',body:'Hi [Name],\n\nYour installation is confirmed for [date]. Our crew will call ahead that morning.\n\nThank you,'},
 {id:'contractor-intro',title:'Contractor Intro',note:'Trade/customer intro',subject:'Olive Glass & Marble',body:'Hi [Contact Name],\n\nThank you for considering Olive Glass & Marble. We specialize in countertops, glass shower enclosures, and mirrors for residential and commercial projects throughout the Fayetteville area.\n\nI would be happy to connect and help with your next project.\n\nThank you,'}
];
const QUICK=[
 ['Reply soon','Thanks for reaching out! I will get back to you shortly.'],
 ['Received','Thanks. I received your message and we will be in touch within one business day.'],
 ['Follow up','Hi [Name], just following up on our previous message. Please let us know if you have any questions.'],
 ['Install confirmed','Hi [Name], your installation is confirmed for [date]. Our crew will call ahead that morning.'],
 ['Ready to template','Hi [Name], we are ready to schedule your template appointment. What days work best for you?'],
 ['Thank you','Thank you for choosing Olive Glass & Marble. It was a pleasure working on your project.']
];
let state={connected:false,folder:"inbox",skip:0,search:"",current:null,more:false,tags:{},reminders:[],pendingAttachment:null,pendingJobAction:'attachment',jobs:[],context:null,canManageTemplates:false,canUseAiDraft:false,aiDraftConfigured:false,aiDraftBusy:false};
const $=id=>document.getElementById(id);
function toast(msg,bad=false){const t=$('toast');t.textContent=msg;t.style.borderColor=bad?'rgba(239,68,68,.5)':'rgba(196,160,90,.3)';t.classList.add('show');setTimeout(()=>t.classList.remove('show'),3000)}
async function api(action,opts={}){const method=opts.method||'GET';const qs=opts.qs?('&'+new URLSearchParams(opts.qs).toString()):'';const fetchOpts={method,credentials:'same-origin'};if(opts.formData){fetchOpts.body=opts.formData}else{fetchOpts.headers={'Content-Type':'application/json'};if(opts.body)fetchOpts.body=JSON.stringify(opts.body)}const res=await fetch(API+'?action='+encodeURIComponent(action)+qs,fetchOpts);let j={};try{j=await res.json()}catch(e){}if(!res.ok||!j.ok)throw new Error(j.error||('Request failed '+res.status));return j}
function esc(s){return String(s??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}
function dateShort(v){if(!v)return'';const d=new Date(v);return isNaN(d)?v:d.toLocaleDateString([], {month:'short',day:'numeric'})}
function dateFull(v){if(!v)return'';const d=new Date(v);return isNaN(d)?v:d.toLocaleString([], {month:'short',day:'numeric',hour:'numeric',minute:'2-digit'})}
function tagBadgeHtml(tag){return tag&&TAGS[tag]?`<span class="tag-badge ${TAG_CLASSES[tag]||''}">${esc(TAGS[tag])}</span>`:''}
function sizeLabel(bytes){bytes=Number(bytes||0);if(bytes<1024)return bytes+' B';if(bytes<1024*1024)return (bytes/1024).toFixed(1)+' KB';return (bytes/1024/1024).toFixed(1)+' MB'}
async function loadTags(){try{const r=await api('tag-list');state.tags=r.tags||{}}catch(e){state.tags={}}}
async function loadReminders(){try{const r=await api('reminders-list');state.reminders=r.reminders||[];renderReminders()}catch(e){state.reminders=[];renderReminders()}}
function renderReminders(){const due=state.reminders.filter(r=>!r.done&&new Date(r.dueAt).getTime()<=Date.now());$('reminder-bar').classList.toggle('on',due.length>0);$('reminder-bar-text').textContent=due.length===1?'1 email reminder is due.':due.length+' email reminders are due.';const panel=$('reminders-panel-list');const open=state.reminders.filter(r=>!r.done).slice().sort((a,b)=>String(a.dueAt).localeCompare(String(b.dueAt)));if(!open.length){panel.className='context-empty';panel.textContent='No open reminders.';return}panel.className='';panel.innerHTML=open.map(r=>`<div class="reminder-card"><div class="reminder-title">${esc(r.subject||'Email reminder')}</div><div class="reminder-due">${esc(dateFull(r.dueAt))}</div>${r.note?`<div class="reminder-note">${esc(r.note)}</div>`:''}<div style="display:flex;gap:6px;flex-wrap:wrap"><button class="btn btn-sm" onclick="snoozeReminder('${esc(r.id)}',1)">Snooze 1h</button><button class="btn btn-sm" onclick="snoozeReminder('${esc(r.id)}',24)">Tomorrow</button><button class="btn btn-sm btn-gold" onclick="doneReminder('${esc(r.id)}')">Done</button></div></div>`).join('')}
async function loadTemplates(){try{const r=await api('templates-list');if(Array.isArray(r.templates)&&r.templates.length)TEMPLATES=r.templates;if(typeof r.canManage!=='undefined')state.canManageTemplates=!!r.canManage}catch(e){}buildTemplateLists()}
function syncTemplateManagerButtons(){document.querySelectorAll('.tpl-manager-action,[data-template-manager]').forEach(el=>{el.style.display=state.canManageTemplates?'inline-flex':'none'})}
function buildTemplateLists(){const cards=TEMPLATES.map(t=>`<div class="tpl-card" data-template="${esc(t.id)}"><div class="tpl-title">${esc(t.title)}</div><div class="tpl-note">${esc(t.note)}</div></div>`).join('');const manageCard='<button type="button" class="tpl-card tpl-add-card" data-template-manager><div class="tpl-title">+ Add Template</div><div class="tpl-note">Manager shared templates</div></button>';$('compose-template-list').innerHTML=cards+manageCard;$('reply-template-list').innerHTML=cards+manageCard;document.querySelectorAll('#compose-template-list .tpl-card[data-template]').forEach(c=>c.onclick=()=>applyComposeTemplate(c.dataset.template));document.querySelectorAll('#reply-template-list .tpl-card[data-template]').forEach(c=>c.onclick=()=>applyReplyTemplate(c.dataset.template));document.querySelectorAll('[data-template-manager],[data-open-template-manager]').forEach(b=>b.onclick=openTemplateManager);syncTemplateManagerButtons()}
function templateById(id){return TEMPLATES.find(t=>t.id===id)||TEMPLATES[0]}
function applyComposeTemplate(id){const t=templateById(id);if(!$('subject-field').value.trim())$('subject-field').value=t.subject;$('html-field').value=t.body}
function applyReplyTemplate(id){$('reply-text').value=templateById(id).body;$('reply-template-drawer').classList.remove('on');$('reply-text').focus()}
function renderQuickReplies(){const row=$('quick-row');row.innerHTML='<span style="font-size:10px;letter-spacing:.12em;text-transform:uppercase;color:#64748b;align-self:center;margin-right:4px">Quick:</span>'+QUICK.map((q,i)=>`<button class="qbtn" data-q="${i}">${esc(q[0])}</button>`).join('');row.querySelectorAll('button[data-q]').forEach(b=>b.onclick=()=>quickReply(QUICK[Number(b.dataset.q)][1]))}
function openTemplateManager(){if(!state.canManageTemplates){toast('Only managers can edit shared templates.',true);return}renderTemplateManager();$('template-modal').classList.add('open')}
function closeTemplateManager(){$('template-modal').classList.remove('open')}
function newTemplateId(){return 'template-'+Date.now()}
function renderTemplateManager(){const list=$('template-editor-list');if(!list)return;list.innerHTML=TEMPLATES.map((t,i)=>`<div class="template-editor-row" data-template-row><div class="template-row-actions"><strong>Template ${i+1}</strong><button class="mbtn mbtn-ghost template-remove" type="button" data-remove-template>Remove</button></div><div class="template-editor-grid"><label>ID<input data-tpl-field="id" value="${esc(t.id)}"></label><label>Title<input data-tpl-field="title" value="${esc(t.title)}"></label><label>Note<input data-tpl-field="note" value="${esc(t.note||'')}"></label><label>Subject<input data-tpl-field="subject" value="${esc(t.subject||'')}"></label></div><label>Body<textarea data-tpl-field="body">${esc(t.body||'')}</textarea></label></div>`).join('')}
function templateEditorRows(){return Array.from(document.querySelectorAll('[data-template-row]')).map((row,i)=>{const get=f=>(row.querySelector(`[data-tpl-field="${f}"]`)||{}).value||'';let id=get('id').trim().replace(/[^a-z0-9._-]+/gi,'-').replace(/^-+|-+$/g,'');if(!id)id='template-'+(i+1);return{id,title:get('title').trim(),note:get('note').trim(),subject:get('subject').trim(),body:get('body')}}).filter(t=>t.title&&String(t.body||'').trim())}
function addTemplateRow(){TEMPLATES=[...TEMPLATES,{id:newTemplateId(),title:'New Template',note:'',subject:'',body:'Hi [Name],\n\n'}];renderTemplateManager();const rows=document.querySelectorAll('[data-template-row]');const last=rows[rows.length-1];if(last){last.scrollIntoView({behavior:'smooth',block:'center'});const title=last.querySelector('[data-tpl-field="title"]');if(title)title.focus()}}
async function saveTemplateManager(){try{const templates=templateEditorRows();if(!templates.length){toast('Add at least one template title and body.',true);return}const r=await api('templates-save',{method:'POST',body:{templates}});TEMPLATES=r.templates||templates;buildTemplateLists();closeTemplateManager();toast('Templates saved')}catch(e){toast(e.message,true)}}
async function resetTemplateManager(){if(!confirm('Reset shared email templates to the OGM defaults?'))return;try{const r=await api('templates-reset',{method:'POST',body:{}});TEMPLATES=r.templates||TEMPLATES;buildTemplateLists();renderTemplateManager();toast('Templates reset')}catch(e){toast(e.message,true)}}
function quickReply(text){$("reply-box").classList.add("on");$("reply-text").value=text;aiClearDraftState();$("reply-text").focus()}function aiIsAutomatedMessage(){if(!state.current)return true;const addr=String(state.current.fromAddr||"").toLowerCase();const subj=String(state.current.subject||"").toLowerCase();return !addr||/^(no-reply|noreply|donotreply)@/.test(addr)||addr.indexOf("mailer-daemon")>=0||addr.indexOf("postmaster@")>=0||subj.indexOf("undeliverable:")===0||subj.indexOf("automatic reply")===0}function aiUpdateButtonVisibility(){const btn=$("ai-draft-btn");if(!btn)return;const on=!!(state.connected&&state.current&&state.canUseAiDraft&&state.aiDraftConfigured&&!aiIsAutomatedMessage());btn.classList.toggle("on",on)}function aiSetBanner(on){const b=$("ai-draft-banner");if(b)b.classList.toggle("on",!!on)}function aiClearDraftState(){state.aiDraftBusy=false;aiSetBanner(false)}async function aiDraftReply(force=false){if(!state.current)return toast("Open an email first",true);if(state.aiDraftBusy)return;if(aiIsAutomatedMessage())return toast("AI drafting is hidden for automated emails",true);const text=$("reply-text");if(text&&text.value.trim()&&!force&&!confirm("Replace the current reply text with an AI draft?"))return;state.aiDraftBusy=true;const btn=$("ai-draft-btn"),icon=$("ai-draft-btn-icon"),label=$("ai-draft-btn-label");if(btn)btn.disabled=true;if(label)label.textContent="Drafting...";try{$("reply-box").classList.add("on");const r=await api("ai-draft-reply",{method:"POST",body:{messageId:state.current.id}});if(text){text.value=r.draft||"";text.focus()}aiSetBanner(true);toast("AI draft ready - review before sending")}catch(e){toast(e.message,true)}finally{state.aiDraftBusy=false;if(btn)btn.disabled=false;if(icon)icon.textContent="AI";if(label)label.textContent="Draft with AI";aiUpdateButtonVisibility()}}function aiDraftAgain(){aiDraftReply(true)}function aiDraftDismiss(){aiSetBanner(false)}
function initReadSplitter(){const splitter=$('read-splitter'),content=$('read-content');if(!splitter||!content)return;let dragging=false;function resizeFromY(y){const r=content.getBoundingClientRect();if(!r.height)return;const minReply=130;const minOpenEmail=165;const maxReply=Math.max(minReply,r.height-minOpenEmail);const next=Math.min(Math.max(r.bottom-y,minReply),maxReply);content.style.setProperty('--reply-pane-h',next+'px')}splitter.addEventListener('pointerdown',e=>{dragging=true;splitter.setPointerCapture&&splitter.setPointerCapture(e.pointerId);e.preventDefault()});splitter.addEventListener('pointermove',e=>{if(dragging)resizeFromY(e.clientY)});function stop(e){if(!dragging)return;dragging=false;try{splitter.releasePointerCapture&&splitter.releasePointerCapture(e.pointerId)}catch(_){}}splitter.addEventListener('pointerup',stop);splitter.addEventListener('pointercancel',stop)}
async function checkStatus(){try{const s=await api('status');state.connected=!!s.connected;state.canManageTemplates=!!s.canManageTemplates;state.canUseAiDraft=!!s.canUseAiDraft;state.aiDraftConfigured=!!s.aiDraftConfigured;aiUpdateButtonVisibility();if($('template-manage-btn'))$('template-manage-btn').style.display=state.canManageTemplates?'':'none';syncTemplateManagerButtons();$('acct-name').textContent=s.connected?(s.name||'Connected'):'Not connected';$('acct-mail').textContent=s.connected?(s.mailbox||''):'';$('connect-btn').style.display=s.connected?'none':'';$('disconnect-btn').style.display=s.connected?'':'none';$('connect-hero').style.display=s.connected?'none':'flex';$('mail-wrap').classList.toggle('on',s.connected);$('connect-note').textContent=s.configured?'':'Microsoft client secret is not installed yet.';if(s.connected){await loadTags();await loadReminders();loadMessages(true);setInterval(loadReminders,5*60*1000)}}catch(e){$('acct-name').textContent='Email Center unavailable';$('connect-note').textContent=e.message}}
async function connect(){try{const r=await api('login-url');location.href=r.url}catch(e){toast(e.message,true)}}async function disconnect(){if(!confirm('Disconnect this Outlook mailbox from your Quoter Tool login?'))return;try{await api('disconnect',{method:'POST',body:{}});state.connected=false;checkStatus()}catch(e){toast(e.message,true)}}
async function loadMessages(reset=false){if(reset){state.skip=0;$('msg-list').innerHTML='<div class="empty">Loading mail...</div>'}try{const r=await api('inbox',{qs:{folder:state.folder,search:state.search,skip:state.skip,top:25}});renderList(r.messages||[],!reset);state.more=!!r.more;state.skip+=(r.messages||[]).length;$('more-btn').style.display=state.more?'':'none'}catch(e){$('msg-list').innerHTML='<div class="empty">'+esc(e.message)+'</div>'}}
function renderList(messages,append){const list=$('msg-list');if(!append)list.innerHTML='';if(!messages.length&&!append){list.innerHTML='<div class="empty">No messages found.</div>';return}for(const m of messages){const div=document.createElement('div');div.className='msg-item'+(m.isRead?'':' unread');div.dataset.id=m.id;div.innerHTML=`<div class="mi-top"><div class="mi-from">${m.isRead?'':'<span class="mi-dot"></span>'}${esc(m.from||'(unknown)')}</div><div class="mi-date">${esc(dateShort(m.date))}</div></div><div class="mi-subj">${esc(m.subject)}${tagBadgeHtml(state.tags[m.id]||'')}</div><div class="mi-prev">${m.hasAttach?'📎 ':''}${esc(m.preview||'')}</div>`;div.addEventListener('click',()=>openMessage(m.id,div));list.appendChild(div)}}
function renderContext(ctx){const body=$("context-body");state.context=ctx||{};if(!ctx){body.className="context-empty";body.textContent="No context loaded.";updateNextPassButtons();return}let html="";function sec(title,items,fn){if(!items||!items.length)return;html+=`<div class="context-section"><h3>${esc(title)}</h3>`+items.map(fn).join("")+"</div>"}sec("Customers",ctx.customers,c=>`<div class="context-item"><a href="${esc(c.url)}" target="_blank" style="color:#e5e7eb;text-decoration:none">${esc(c.name)}</a><span class="context-meta">${esc([c.phone,c.email].filter(Boolean).join(" · "))}</span><div class="context-mini-actions"><button class="btn btn-sm" type="button" data-email-save-customer="${esc(c.id)}">Save email history</button></div></div>`);sec("Quotes",ctx.quotes,q=>`<div class="context-item">${esc(q.quoteNumber)}<span class="context-meta">${esc(q.label||"Quote")}${q.total?" · $"+Number(q.total).toFixed(2):""}</span></div>`);sec("Jobs / ClickUp",ctx.jobs,j=>{const cust=(ctx.customers&&ctx.customers[0])?ctx.customers[0].id:"";const link=j.url?`<a href="${esc(j.url)}" target="_blank" style="color:#e5e7eb;text-decoration:none">${esc(j.name||j.taskId)}</a>`:esc(j.name||j.taskId);return `<div class="context-item">${link}<span class="context-meta">${esc(j.taskId||"")}</span><div class="context-mini-actions"><button class="btn btn-sm" type="button" data-email-save-job="${esc(j.taskId||"")}" data-job-name="${esc(j.name||"")}" data-customer-id="${esc(cust)}">Save as job note</button></div></div>`});if(!html)html="<div class=\"context-empty\">No matching OGM customer, quote, or job was found for this message. Use Next Pass to create a customer or lead from this email.</div>";body.className="";body.innerHTML=html;updateNextPassButtons()}
function currentContextCustomer(){return state.context&&state.context.customers&&state.context.customers.length?state.context.customers[0]:null}
function currentContextJob(){return state.context&&state.context.jobs&&state.context.jobs.length?state.context.jobs[0]:null}
function updateNextPassButtons(){const has=!!state.current;["next-link-customer","next-create-lead","next-save-job-note"].forEach(id=>{const b=$(id);if(b)b.disabled=!has});const jobBtn=$("next-save-job-note");if(jobBtn)jobBtn.title=currentContextJob()?"Save this email as a note on the matched job":"Search and select a job to save this email as a note."}
async function saveEmailHistory(customerId,opts={}){if(!state.current)return toast("Open an email first",true);if(!customerId)return toast("Choose or create a customer first",true);try{const r=await api("save-email-history",{method:"POST",body:{messageId:state.current.id,customerId,tag:opts.tag||state.tags[state.current.id]||"",jobId:opts.jobId||"",jobName:opts.jobName||""}});toast("Email saved to customer history");return r}catch(e){toast(e.message,true);throw e}}
async function createOrLinkCustomerFromEmail(){if(!state.current)return toast("Open an email first",true);const existing=currentContextCustomer();if(existing){await saveEmailHistory(existing.id);return}try{const r=await api("create-customer-from-email",{method:"POST",body:{messageId:state.current.id}});const customer=r.customer||{};toast(r.created?"Customer created and email saved":"Existing customer linked and email saved");state.context=state.context||{};state.context.customers=[customer].concat(state.context.customers||[]);renderContext(state.context)}catch(e){toast(e.message,true)}}
async function createLeadFromEmail(){if(!state.current)return toast("Open an email first",true);try{await api("create-lead-from-email",{method:"POST",body:{messageId:state.current.id}});toast("Lead saved from email")}catch(e){toast(e.message,true)}}
async function saveEmailAsJobNote(taskId="",jobName="",customerId=""){if(!state.current)return toast("Open an email first",true);const job=taskId?{taskId,name:jobName}:currentContextJob();if(!job||!job.taskId){openJobNoteModal();return}const cust=customerId||(currentContextCustomer()?currentContextCustomer().id:"");try{await api("save-email-job-note",{method:"POST",body:{messageId:state.current.id,taskId:job.taskId,taskName:job.name||"",customerId:cust}});toast("Email saved as job note")}catch(e){toast(e.message,true)}}
function resizeBodyFrame(){const frame=$('body-frame');if(!frame)return;try{const doc=frame.contentDocument;if(!doc)return;const h=Math.max(doc.documentElement.scrollHeight||0,doc.body?doc.body.scrollHeight:0,260);frame.style.height=h+'px'}catch(_){}}
function setBodyFrameHtml(html){const frame=$('body-frame');if(!frame)return;const body=String(html||'<p style="color:#64748b">This message has no readable body.</p>');frame.style.height='260px';frame.onload=resizeBodyFrame;frame.srcdoc=`<!doctype html><html><head><base target="_blank"><style>html,body{overflow:visible}body{font-family:Arial,sans-serif;line-height:1.55;color:#111;padding:18px;margin:0;background:#fff}img{max-width:100%;height:auto}table{max-width:100%}</style></head><body>${body}</body></html>`;setTimeout(resizeBodyFrame,80);setTimeout(resizeBodyFrame,500)}
function emailListItemById(id){return Array.from(document.querySelectorAll('.msg-item')).find(n=>n.dataset.id===id)||null}
function setMessageReadUi(id,isRead){const item=emailListItemById(id);if(!item)return;item.classList.toggle('unread',!isRead);const from=item.querySelector('.mi-from');if(!from)return;const dot=from.querySelector('.mi-dot');if(isRead&&dot)dot.remove();else if(!isRead&&!dot)from.insertAdjacentHTML('afterbegin','<span class="mi-dot"></span>')}
async function markMessageReadOnOpen(id){if(!id)return;setMessageReadUi(id,true);if(state.current&&state.current.id===id){state.current.isRead=true;$('mark-btn').textContent='Mark Unread'}try{await api('markread',{method:'POST',body:{id,read:true}})}catch(e){console.warn('Could not mark message read',e)}}
async function openMessage(id,node){document.querySelectorAll('.msg-item').forEach(n=>n.classList.remove('sel'));if(node)node.classList.add('sel');try{const r=await api('message',{qs:{id}});const msg=r.message||{};state.current=msg;state.tags[msg.id]=msg.tag||state.tags[msg.id]||'';$('read-empty').style.display='none';$('read-content').style.display='flex';$('read-subj').innerHTML=esc(msg.subject||'(no subject)')+tagBadgeHtml(state.tags[msg.id]||'');$('read-meta').innerHTML=`<b>From:</b> ${esc(msg.from||msg.fromAddr)}<br><b>To:</b> ${esc((msg.to||[]).join(', '))}<br><b>Date:</b> ${esc(msg.date||'')}`;$('mark-btn').textContent=msg.isRead?'Mark Unread':'Mark Read';setBodyFrameHtml(msg.body||'');renderAttachments(msg.attachments||[]);renderContext(r.context);renderTagMenu();$('reply-box').classList.remove('on');$('reply-pane').classList.remove('active');$('reply-template-drawer').classList.remove('on');$("reply-text").value="";aiClearDraftState();aiUpdateButtonVisibility();$("quick-row").classList.add('on');if(msg.isRead===false)markMessageReadOnOpen(msg.id);else if(node)setMessageReadUi(msg.id,true)}catch(e){toast(e.message,true)}}
function renderTagMenu(){const current=state.current?state.tags[state.current.id]||'':'';$('tag-menu').innerHTML=Object.entries(TAGS).map(([k,label])=>`<div class="tag-item ${current===k?'active':''}" data-tag="${k}">${esc(label)}</div>`).join('')+`<div class="tag-item" data-tag="">Remove tag</div>`;$('tag-menu').querySelectorAll('.tag-item').forEach(i=>i.onclick=()=>setTag(i.dataset.tag||''))}
async function setTag(tag){if(!state.current)return;try{await api('tag-set',{method:'POST',body:{messageId:state.current.id,tag}});if(tag)state.tags[state.current.id]=tag;else delete state.tags[state.current.id];$('tag-picker').classList.remove('open');$('read-subj').innerHTML=esc(state.current.subject||'(no subject)')+tagBadgeHtml(tag);const item=document.querySelector(`.msg-item[data-id="${CSS.escape(state.current.id)}"] .mi-subj`);if(item)item.innerHTML=esc(state.current.subject||'')+tagBadgeHtml(tag);toast(tag?'Tagged '+TAGS[tag]:'Tag removed')}catch(e){toast(e.message,true)}}
function renderAttachments(attachments){const bar=$('attach-bar'),chips=$('attach-chips');if(!attachments.length){bar.classList.remove('on');chips.innerHTML='';return}bar.classList.add('on');chips.innerHTML=attachments.map((a,i)=>{const url=API+'?action=attachment-download&messageId='+encodeURIComponent(state.current.id)+'&attachmentId='+encodeURIComponent(a.id)+'&name='+encodeURIComponent(a.name||'attachment');return `<span class="attach-chip">📎 <span>${esc(a.name||'Attachment')} <small style="color:#94a3b8">${esc(sizeLabel(a.size))}</small></span><a href="${url}" target="_blank">Open</a><button class="btn btn-sm" data-att="${i}">Job</button></span>`}).join('');chips.querySelectorAll('button[data-att]').forEach(b=>b.onclick=()=>openJobModal(attachments[Number(b.dataset.att)]))}
function showCompose(prefill={}){$('to-field').value=(prefill.to||[]).join(', ');$('cc-field').value=(prefill.cc||[]).join(', ');$('subject-field').value=prefill.subject||'';$('html-field').value=prefill.html||'';if($('compose-files'))$('compose-files').value='';$('compose-modal').classList.add('open')}function hideCompose(){$('compose-modal').classList.remove('open')}function splitEmails(v){return String(v||'').split(/[;,]/).map(s=>s.trim()).filter(Boolean)}function hasTemplatePlaceholders(text){return /\[[^\]\n]{2,80}\]/.test(String(text||''))}function confirmNoTemplatePlaceholders(text){return !hasTemplatePlaceholders(text)||confirm('This email still has bracketed placeholders like [Name] or [date]. Send anyway?')}function appendFiles(fd,inputId){const input=$(inputId);if(!input||!input.files)return;Array.from(input.files).forEach(file=>fd.append('attachments[]',file,file.name))}function subjectWithPrefix(prefix,subject){subject=String(subject||'(no subject)').trim();return subject.toLowerCase().startsWith(prefix.toLowerCase()+':')?subject:prefix+': '+subject}
async function sendCompose(){try{const subject=$('subject-field').value;const body=$('html-field').value;if(!confirmNoTemplatePlaceholders(subject+'\n'+body))return;const fd=new FormData();fd.append('to',JSON.stringify(splitEmails($('to-field').value)));fd.append('cc',JSON.stringify(splitEmails($('cc-field').value)));fd.append('subject',subject);fd.append('html',body.replace(/\n/g,'<br>'));appendFiles(fd,'compose-files');await api('send',{method:'POST',formData:fd});hideCompose();toast('Email sent');if(state.folder==='sentitems')loadMessages(true)}catch(e){toast(e.message,true)}}
function openReply(all=false){if(!state.current)return;$("reply-pane").classList.add("active");$("reply-box").classList.add("on");$("reply-mode").value=all?"replyAll":"reply";aiUpdateButtonVisibility();$("reply-text").focus()}function openForward(){if(!state.current)return;const msg=state.current;const header='\n\n---------- Forwarded message ----------\nFrom: '+(msg.from||msg.fromAddr||'')+' <'+(msg.fromAddr||'')+'>\nDate: '+(msg.date||'')+'\nSubject: '+(msg.subject||'')+'\nTo: '+((msg.to||[]).join(', '))+'\n\n';const bodyText=(msg.body||'').replace(/<br\s*\/?>/gi,'\n').replace(/<\/(p|div|li|tr|h[1-6])>/gi,'\n').replace(/<[^>]+>/g,'').replace(/&nbsp;/g,' ');showCompose({to:[],cc:[],subject:subjectWithPrefix('FW',msg.subject),html:header+bodyText})}async function sendReply(){if(!state.current)return;try{const body=$("reply-text").value;if($("ai-draft-banner")&&$("ai-draft-banner").classList.contains("on")&&!confirm("This reply was AI-drafted. Have you reviewed it for accuracy?"))return;if(!confirmNoTemplatePlaceholders(body))return;const fd=new FormData();fd.append('id',state.current.id);fd.append('html',body.replace(/\n/g,"<br>"));fd.append('all',$("reply-mode").value==="replyAll"?'1':'0');appendFiles(fd,'reply-files');await api("reply",{method:"POST",formData:fd});$("reply-box").classList.remove("on");$("reply-pane").classList.remove("active");$("reply-text").value="";if($("reply-files"))$("reply-files").value='';aiClearDraftState();toast("Reply sent")}catch(e){toast(e.message,true)}}
async function markCurrent(){if(!state.current)return;try{const nextRead=!state.current.isRead;await api('markread',{method:'POST',body:{id:state.current.id,read:nextRead}});state.current.isRead=nextRead;$('mark-btn').textContent=state.current.isRead?'Mark Unread':'Mark Read';setMessageReadUi(state.current.id,state.current.isRead);toast('Message updated')}catch(e){toast(e.message,true)}}
function openReminderModal(){if(!state.current)return;$('reminder-note').value='';setReminderHours(24);$('reminder-modal').classList.add('open')}function closeReminderModal(){$('reminder-modal').classList.remove('open')}function setReminderHours(hours){const d=new Date(Date.now()+hours*3600000);d.setSeconds(0,0);$('reminder-due').value=d.toISOString().slice(0,16)}async function saveReminder(){if(!state.current)return;const v=$('reminder-due').value;if(!v){toast('Pick a reminder time.',true);return}try{await api('reminder-set',{method:'POST',body:{messageId:state.current.id,subject:state.current.subject||'',fromAddr:state.current.fromAddr||'',dueAt:new Date(v).toISOString(),note:$('reminder-note').value}});closeReminderModal();await loadReminders();toast('Reminder saved')}catch(e){toast(e.message,true)}}async function doneReminder(id){try{await api('reminder-done',{method:'POST',body:{id}});await loadReminders()}catch(e){toast(e.message,true)}}async function snoozeReminder(id,hours){const due=new Date(Date.now()+hours*3600000).toISOString();try{await api('reminder-snooze',{method:'POST',body:{id,dueAt:due}});await loadReminders();toast('Reminder snoozed')}catch(e){toast(e.message,true)}}
function openJobModal(att){state.pendingJobAction="attachment";state.pendingAttachment=att;$("job-attach-name").textContent="Attachment: "+(att.name||"Attachment")+" · "+sizeLabel(att.size);$("job-search").value=state.current?(state.current.subject||""):"";$("job-list").innerHTML="<div class=\"context-empty\">Search for a job to attach this email file.</div>";$("job-modal").classList.add("open");searchJobs()}
function openJobNoteModal(){state.pendingJobAction="note";state.pendingAttachment=null;$("job-attach-name").textContent="Save this email as a note on a job";$("job-search").value=state.current?(state.current.subject||""):"";$("job-list").innerHTML="<div class=\"context-empty\">Search for the job this email belongs to.</div>";$("job-modal").classList.add("open");searchJobs()}
function closeJobModal(){$("job-modal").classList.remove("open");state.pendingAttachment=null;state.pendingJobAction="attachment"}
async function searchJobs(){try{const r=await api("job-search",{qs:{q:$("job-search").value.trim()}});state.jobs=r.jobs||[];renderJobs()}catch(e){$("job-list").innerHTML="<div class=\"context-empty\">"+esc(e.message)+"</div>"}}
function renderJobs(){const list=$("job-list");if(!state.jobs.length){list.innerHTML="<div class=\"context-empty\">No matching jobs found.</div>";return}list.innerHTML=state.jobs.map((j,i)=>`<button class="job-pick" data-job="${i}"><strong>${esc(j.name||"ClickUp job")}</strong><span>${esc([j.customer,j.taskId].filter(Boolean).join(" · "))}</span></button>`).join("");list.querySelectorAll("button[data-job]").forEach(b=>b.onclick=()=>sendJobModalSelection(state.jobs[Number(b.dataset.job)]))}
async function sendJobModalSelection(job){if(state.pendingJobAction==="note"){closeJobModal();saveEmailAsJobNote(job.taskId,job.name||"",currentContextCustomer()?currentContextCustomer().id:"");return}sendAttachmentToJob(job)}
async function sendAttachmentToJob(job){const att=state.pendingAttachment;if(!state.current||!att||!job)return;try{await api('attach-to-job',{method:'POST',body:{messageId:state.current.id,attachmentId:att.id,attachmentName:att.name,contentType:att.contentType,taskId:job.taskId,taskName:job.name}});closeJobModal();toast('Attachment saved to job')}catch(e){toast(e.message,true)}}
if($("context-body"))$("context-body").addEventListener("click",e=>{const cust=e.target.closest("[data-email-save-customer]");if(cust){saveEmailHistory(cust.dataset.emailSaveCustomer);return}const job=e.target.closest("[data-email-save-job]");if(job){saveEmailAsJobNote(job.dataset.emailSaveJob||"",job.dataset.jobName||"",job.dataset.customerId||"")}});
if($("next-link-customer"))$("next-link-customer").onclick=createOrLinkCustomerFromEmail;
if($("next-create-lead"))$("next-create-lead").onclick=createLeadFromEmail;
if($("next-save-job-note"))$("next-save-job-note").onclick=()=>saveEmailAsJobNote();
document.querySelectorAll(".tab").forEach(b=>b.addEventListener('click',()=>{document.querySelectorAll('.tab').forEach(x=>x.classList.remove('on'));b.classList.add('on');state.folder=b.dataset.folder;state.search='';$('search').value='';loadMessages(true)}));
$('connect-btn').onclick=connect;$('hero-connect-btn').onclick=connect;$('disconnect-btn').onclick=disconnect;$('template-manage-btn').onclick=openTemplateManager;$('template-close').onclick=closeTemplateManager;$('template-cancel').onclick=closeTemplateManager;$('template-add').onclick=addTemplateRow;if($('template-add-top'))$('template-add-top').onclick=addTemplateRow;$('template-save').onclick=saveTemplateManager;$('template-reset').onclick=resetTemplateManager;$('template-editor-list').addEventListener('click',e=>{const b=e.target.closest('[data-remove-template]');if(b){const row=b.closest('[data-template-row]');if(row)row.remove()}});$('compose-btn').onclick=()=>showCompose();$('modal-close').onclick=hideCompose;$('compose-cancel').onclick=hideCompose;$('compose-send').onclick=sendCompose;$('search-btn').onclick=()=>{state.search=$('search').value.trim();loadMessages(true)};$('search').addEventListener('keydown',e=>{if(e.key==='Enter')$('search-btn').click()});$('more-btn').onclick=()=>loadMessages(false);$('reply-btn').onclick=()=>openReply(false);$('reply-all-btn').onclick=()=>openReply(true);$('forward-btn').onclick=openForward;$('send-reply').onclick=sendReply;$("cancel-reply").onclick=()=>{$("reply-box").classList.remove("on");$("reply-pane").classList.remove("active");$("reply-text").value="";if($("reply-files"))$("reply-files").value="";aiClearDraftState()};$('mark-btn').onclick=markCurrent;$('tag-picker-btn').onclick=e=>{e.stopPropagation();$('tag-picker').classList.toggle('open')};document.addEventListener('click',e=>{if($('tag-picker')&&!$('tag-picker').contains(e.target))$('tag-picker').classList.remove('open')});$("reply-template-btn").onclick=()=>$("reply-template-drawer").classList.toggle("on");if($("ai-draft-btn"))$("ai-draft-btn").onclick=()=>aiDraftReply(false);if($("ai-draft-again"))$("ai-draft-again").onclick=()=>aiDraftAgain();if($("ai-draft-dismiss"))$("ai-draft-dismiss").onclick=aiDraftDismiss;$('remind-btn').onclick=openReminderModal;$('show-reminders-btn').onclick=()=>$('reminders-panel').scrollIntoView({behavior:'smooth',block:'start'});$('reminder-close').onclick=closeReminderModal;$('reminder-cancel').onclick=closeReminderModal;$('reminder-save').onclick=saveReminder;document.querySelectorAll('[data-rem-hours]').forEach(b=>b.onclick=()=>setReminderHours(Number(b.dataset.remHours)));$('job-close').onclick=closeJobModal;$('job-cancel').onclick=closeJobModal;$('job-search-btn').onclick=searchJobs;$('job-search').addEventListener('keydown',e=>{if(e.key==='Enter')searchJobs()});
initReadSplitter();loadTemplates();renderQuickReplies();checkStatus();
</script>
</body>
</html>
